import './css/App.css';
import React, { createRef } from 'react';
import IconCheckbox from './checkbox';

const parseJSON = obj => {
  if ( typeof obj !== 'object' ) {
    return obj;
  }
  else if ( Array.isArray( obj ) ) {
    const arr = [ ...obj ];

    for ( let i = 0; i < obj.length; i++ ) {
      arr[ i ] = parseJSON( arr[ i ] );
    }
    return arr;
  }

  const returnObj = {};
  const keys = Object.keys( obj ).sort( (
    a, b
  ) => {
    const aT = a.toLowerCase();
    const bT = b.toLowerCase();

    return aT > bT ? 1 : aT < bT ? -1 : 0;
  } );

  for ( let i = 0; i < keys.length; i++ ) {
    const key = keys[ i ];
    const val = obj[ key ];

    returnObj[ key ] = parseJSON( val );
  }

  return returnObj;
};

class App extends React.Component {
  state = {
    in: '',
    out: '',
    prettify: true,
    indent: 2,
  };

  textareaIn = createRef();

  render = () => <div className="App">
    <textarea
      className="in"
      placeholder="Paste JSON here"
      value={this.state.in}
      onInput={this.handleInput}
      ref={this.textareaIn}
      autoFocus
    />
    <div onChange={this.handleChange} className="settings">
      <div className="settings-row">
        <div className="label">Prettify</div>
        <div
          className="input hasSvg"
          onClick={this.toggleCheckbox}
          data-state-key="prettify"
        >
          {<IconCheckbox checked={this.state.prettify} />}
        </div>
      </div>
      <div
        className={`settings-row${ this.state.prettify ? '' : ' disabled' }`}
      >
        <div className="label">Indent</div>
        <input
          type="number"
          data-setting="indent"
          className="input"
          defaultValue={this.state.indent}
          min="0"
          disabled={this.state.prettify === false}
        />
      </div>
    </div>
    <textarea
      className="out"
      value={this.state.out}
      readOnly
      onClick={this.selectAll}
    />
  </div>;

  selectAll = e => {
    e.target.focus();
    e.target.select();
  };

  toggleCheckbox = e => {
    this.setState(
      state => {
        const { stateKey } = e.target.closest( '[data-state-key]' ).dataset;

        return {
          [ stateKey ]: state[ stateKey ] === false,
        };
      },
      this.handleInput
    );
  };

  changeHandlers = {
    indent: (
      target, state
    ) => {
      const val = target.value;

      if ( isFinite( val ) && +val >= 0 ) {
        return +target.value;
      }
      return state.indent;
    },
  };

  handleChange = e => {
    this.setState(
      state => {
        const { setting } = e.target.dataset;

        return {
          [ setting ]: this.changeHandlers[ setting ](
            e.target,
            state
          ),
        };
      },
      this.handleInput
    );
  };

  handleInput = () => {
    const textarea = this.textareaIn.current;
    const { value } = textarea;

    this.setState( { in: value } );
    try {
      const valueNoComments = value.replace(
        /\/{2}.*?(?=\n)|\/\*.*?\*\//gsu,
        ''
      );

      const json = parseJSON( JSON.parse( valueNoComments ) );

      this.setState( {
        out: JSON.stringify(
          json,
          ...this.state.prettify ? [ null, this.state.indent ] : []
        ),
      } );
    }
    catch {
      this.setState( { out: '' } );
    }
  };
}

export default App;
